const COMMENTS_FILE = path.join(process.cwd(), 'comments-store.json');

function readLocalComments(fileId: string): any[] {
  try {
    if (!fs.existsSync(COMMENTS_FILE)) {
      return [];
    }
    const fileContent = fs.readFileSync(COMMENTS_FILE, 'utf-8');
    if (!fileContent.trim()) return [];
    const data = JSON.parse(fileContent);
    return data[fileId] || [];
  } catch (e) {
    console.error("Error reading local comments", e);
    return [];
  }
}

function saveLocalComment(fileId: string, comment: any) {
  try {
    let data: Record<string, any[]> = {};
    if (fs.existsSync(COMMENTS_FILE)) {
      const fileContent = fs.readFileSync(COMMENTS_FILE, 'utf-8');
      if (fileContent.trim()) {
        data = JSON.parse(fileContent);
      }
    }
    if (!data[fileId]) {
      data[fileId] = [];
    }
    data[fileId].unshift(comment);
    fs.writeFileSync(COMMENTS_FILE, JSON.stringify(data, null, 2), 'utf-8');
  } catch (e) {
    console.error("Error saving local comment", e);
  }
}

function parseEpisodeNumber(title: string): number {
  // First, try to find any raw number in the title
  const numMatch = title.match(/\b(\d+)\b/);
  if (numMatch) {
    return parseInt(numMatch[1], 10);
  }

  // Next, look for Arabic ordinal words
  const titleNormalized = title.replace(/[أإآا]/g, 'ا').replace(/ة/g, 'ه').trim();
  
  const ordinals: { [key: string]: number } = {
    'الاولى': 1, 'الاول': 1,
    'الثانيه': 2, 'الثاني': 2,
    'الثالثه': 3, 'الثالث': 3,
    'الرابعه': 4, 'الرابع': 4,
    'الخامسه': 5, 'الخامس': 5,
    'السادسه': 6, 'السادس': 6,
    'السابعه': 7, 'السابع': 7,
    'الثامنه': 8, 'الثامن': 8,
    'التاسعه': 9, 'التاسع': 9,
    'العاشره': 10, 'العاشر': 10,
    'الحاديه عشر': 11, 'الحادي عشر': 11,
    'الثانيه عشر': 12, 'الثاني عشر': 12,
    'الثالثه عشر': 13, 'الثالث عشر': 13,
    'الرابعه عشر': 14, 'الرابع عشر': 14,
    'الخامسه عشر': 15, 'الخامس عشر': 15,
    'السادسه عشر': 16, 'السادس عشر': 16,
    'السابعه عشر': 17, 'السابع عشر': 17,
    'الثامنه عشر': 18, 'الثامن عشر': 18,
    'التاسعه عشر': 19, 'التاسع عشر': 19,
    'العشرون': 20, 'العشرين': 20
  };

  for (const key of Object.keys(ordinals)) {
    const normKey = key.replace(/[أإآا]/g, 'ا').replace(/ة/g, 'ه');
    if (titleNormalized.includes(normKey)) {
      return ordinals[key];
    }
  }

  return 999; // fallback for sorting
}

app.get('/api/comments/:fileId', async (req, res) => {
  const { fileId } = req.params;
  try {
    const url = `https://www.googleapis.com/drive/v3/files/${fileId}/comments?key=${GDRIVE_API_KEY}&fields=comments(id,content,author(displayName,photoLink),createdTime,resolved,replies(id,content,author(displayName,photoLink),createdTime))`;
    const driveRes = await axios.get(url);
    const driveComments = driveRes.data.comments || [];
    
    const mappedDrive = driveComments.map((c: any) => ({
      id: c.id,
      content: c.content,
      author: {
        displayName: c.author?.displayName || 'مستخدم Google Drive',
        photoLink: c.author?.photoLink || ''
      },
      createdTime: c.createdTime,
      resolved: c.resolved || false,
      replies: (c.replies || []).map((r: any) => ({
        id: r.id,
        content: r.content,
        author: {
          displayName: r.author?.displayName || 'مستخدم Google Drive',
          photoLink: r.author?.photoLink || ''
        },
        createdTime: r.createdTime
      }))
    }));

    const localComments = readLocalComments(fileId);
    
    // Merge drive comments and local comments cleanly
    const mergedMap = new Map();
    
    // 1. Add local comments
    localComments.forEach((c: any) => {
      mergedMap.set(c.id, {
        id: c.id,
        content: c.content,
        author: c.author,
        createdTime: c.createdTime,
        resolved: c.resolved || false,
        replies: c.replies || []
      });
    });

    // 2. Add/Overwrite with drive comments, merging replies
    mappedDrive.forEach((c: any) => {
      const existing = mergedMap.get(c.id);
      const mergedReplies = [...(c.replies || [])];
      
      if (existing && existing.replies) {
        existing.replies.forEach((lr: any) => {
          // Keep local reply if it's not already in the drive replies
          if (lr.id.startsWith('local_reply_') && !mergedReplies.some((dr: any) => dr.content === lr.content)) {
            mergedReplies.push(lr);
          }
        });
      }

      mergedMap.set(c.id, {
        id: c.id,
        content: c.content,
        author: c.author,
        createdTime: c.createdTime,
        resolved: c.resolved || false,
        replies: mergedReplies
      });
    });

    const merged = Array.from(mergedMap.values());
    // Sort by createdTime descending
    merged.sort((a, b) => new Date(b.createdTime).getTime() - new Date(a.createdTime).getTime());
    
    return res.json({ comments: merged });
  } catch (error: any) {
    const localComments = readLocalComments(fileId);
    return res.json({ comments: localComments });
  }
});

