app.post('/api/comments/:fileId/:commentId/replies', async (req, res) => {
  const { fileId, commentId } = req.params;
  const { content, authorName } = req.body;

  if (!content || !content.trim()) {
    return res.status(400).json({ error: 'Reply content is required' });
  }

  const newReply = {
    id: 'local_reply_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9),
    content: content.trim(),
    author: {
      displayName: authorName || 'مستخدم BCN+',
      photoLink: ''
    },
    createdTime: new Date().toISOString()
  };

  try {
    // Read comments file
    let data: Record<string, any[]> = {};
    if (fs.existsSync(COMMENTS_FILE)) {
      const fileContent = fs.readFileSync(COMMENTS_FILE, 'utf-8');
      if (fileContent.trim()) {
        data = JSON.parse(fileContent);
      }
    }
    const commentsList = data[fileId] || [];
    const parentComment = commentsList.find((c: any) => c.id === commentId);
    if (parentComment) {
      if (!parentComment.replies) parentComment.replies = [];
      parentComment.replies.push(newReply);
    } else {
      // Create parent in local if it exists in drive but not yet in local
      const placeholderParent = {
        id: commentId,
        content: 'تعليق Google Drive',
        author: { displayName: 'مستخدم Google Drive', photoLink: '' },
        createdTime: new Date().toISOString(),
        resolved: false,
        replies: [newReply]
      };
      commentsList.push(placeholderParent);
      data[fileId] = commentsList;
    }
    fs.writeFileSync(COMMENTS_FILE, JSON.stringify(data, null, 2), 'utf-8');
  } catch (e) {
    console.error("Error saving local reply", e);
  }

  try {
    const url = `https://www.googleapis.com/drive/v3/files/${fileId}/comments/${commentId}/replies?key=${GDRIVE_API_KEY}`;
    await axios.post(url, { content: content.trim() });
  } catch (err: any) {
    // Fail silently
  }

  return res.json({ success: true, reply: newReply });
});

async function getDriveFiles(query: string) {
  const url = `https://www.googleapis.com/drive/v3/files?q=${encodeURIComponent(query)}&key=${GDRIVE_API_KEY}&fields=files(id,name,mimeType,parents,thumbnailLink,size,videoMediaMetadata,description)&pageSize=1000`;
  const response = await axios.get(url);
  return response.data.files;
}

// Function to fetch info.json content
async function getDriveFileContent(fileId: string) {
  const url = `https://www.googleapis.com/drive/v3/files/${fileId}?alt=media&key=${GDRIVE_API_KEY}`;
  try {
    const response = await axios.get(url);
    return response.data;
  } catch (e) {
    return null;
  }
}

async function scanLibrary() {
  console.log("Scanning Drive Library...");
  
  // We'll do a flat query for all files and folders that are descendants?
  // Drive API doesn't support deep descendant queries easily.
  // Instead, let's just fetch everything in the drive and build the tree if it's a dedicated folder,
  // BUT without a service account we can only search files we have access to. 
  // Let's use a simpler approach: get children of root, then children of those...
  
  const rootChildren = await getDriveFiles(`'${ROOT_FOLDER_ID}' in parents and trashed = false`);
  
  let library: any = {
    movies: [],
    series: [],
    kids: [],
    documentary: [],
    islamic: []
  };

  const getDirectLink = (id: string) => `/api/video/${id}`;
  const getImageLink = (id: string) => `/api/image/${id}`;

  for (const category of rootChildren) {
    if (category.mimeType !== 'application/vnd.google-apps.folder') continue;
    
    let catName = category.name.toLowerCase();
    let targetList: any[] = [];
    
    if (catName.includes('movies') || catName.includes('افلام')) targetList = library.movies;
    else if (catName.includes('series') || catName.includes('مسلسلات')) targetList = library.series;
    else if (catName.includes('kids') || catName.includes('اطفال')) targetList = library.kids;
    else if (catName.includes('documentary') || catName.includes('وثائقي')) targetList = library.documentary;
    else if (catName.includes('religious') || catName.includes('islamic') || catName.includes('إسلامي') || catName.includes('اسلامي')) targetList = library.islamic;

    const items = await getDriveFiles(`'${category.id}' in parents and trashed = false`);
    
    for (const itemFolder of items) {
      if (itemFolder.mimeType !== 'application/vnd.google-apps.folder') continue;
      
      const files = await getDriveFiles(`'${itemFolder.id}' in parents and trashed = false`);
      
      let coverUrl = '';
      let videoUrl = '';
      let trailerUrl = '';
      let videoSize = '';
      let videoId = '';
      let trailerId = '';
       let videoDuration: number | undefined;
      let info: any = {};
      let videoThumbnail = '';
      
      let fallbackVideoUrl = '';
      let fallbackVideoId = '';
      let fallbackVideoSize = '';
      let fallbackVideoDuration: number | undefined;
      
      for (const file of files) {
        if (file.name.toLowerCase().includes('cover') && file.mimeType.startsWith('image/')) {
          coverUrl = file.thumbnailLink ? file.thumbnailLink.replace('=s220', '=s800') : getImageLink(file.id);
        } else if (file.name.toLowerCase().includes('info.json')) {
          const content = await getDriveFileContent(file.id);
          if (content) info = content;
        } else if (file.mimeType.startsWith('video/')) {
          if (file.name.toLowerCase().includes('trailer')) {
            trailerUrl = getDirectLink(file.id);
            trailerId = file.id;
          } else {
            const expectedName = (itemFolder.name + '.mp4').toLowerCase();
            if (file.name.toLowerCase() === expectedName) {
              videoUrl = getDirectLink(file.id);
              videoId = file.id;
              videoSize = file.size || '';
              videoDuration = file.videoMediaMetadata?.durationMillis ? parseInt(file.videoMediaMetadata.durationMillis) / 1000 : undefined;
              videoThumbnail = file.thumbnailLink || '';
            } else {
              fallbackVideoUrl = getDirectLink(file.id);
              fallbackVideoId = file.id;
              fallbackVideoSize = file.size || '';
              fallbackVideoDuration = file.videoMediaMetadata?.durationMillis ? parseInt(file.videoMediaMetadata.durationMillis) / 1000 : undefined;
              if (!videoThumbnail) {
                videoThumbnail = file.thumbnailLink || '';
              }
            }
          }
        } else if (file.mimeType === 'application/vnd.google-apps.folder' && file.name.toLowerCase() === 'trailer') {
           const trailerFiles = await getDriveFiles(`'${file.id}' in parents and trashed = false`);
           const trailerVideo = trailerFiles.find((f: any) => f.mimeType.startsWith('video/'));
           if (trailerVideo) {
             trailerUrl = getDirectLink(trailerVideo.id);
             trailerId = trailerVideo.id;
           }
        }
      }
      
      if (!videoUrl) {
        videoUrl = fallbackVideoUrl;
        videoId = fallbackVideoId;
        videoSize = fallbackVideoSize;
        videoDuration = fallbackVideoDuration;
      }
      
      // Handle seasons if this is a series
      let seasons: any[] = [];
      const isSeries = catName.includes('series') || catName.includes('مسلسلات');
      
      if (isSeries) {
        const seasonFolders = files.filter((f: any) => f.mimeType === 'application/vnd.google-apps.folder' && f.name.toLowerCase() !== 'trailer');
        if (seasonFolders.length > 0) {
          seasonFolders.sort((a: any, b: any) => a.name.localeCompare(b.name, undefined, { numeric: true, sensitivity: 'base' }));
          
          for (const sf of seasonFolders) {
            try {
              const epFiles = await getDriveFiles(`'${sf.id}' in parents and trashed = false`);
              const seasonEpisodes: any[] = [];
              let seasonCover = '';
              let seasonInfo: any = {};
              
              for (const epFile of epFiles) {
                if (epFile.name.toLowerCase().includes('cover') && epFile.mimeType.startsWith('image/')) {
                  seasonCover = epFile.thumbnailLink ? epFile.thumbnailLink.replace('=s220', '=s800') : getImageLink(epFile.id);
                } else if (epFile.name.toLowerCase().includes('info.json')) {
                  const content = await getDriveFileContent(epFile.id);
                  if (content) seasonInfo = content;
                } else if (epFile.mimeType.startsWith('video/')) {
                  let titleStr = epFile.name;
                  let epRating = undefined;
                  
                  // 1. Remove standard video extension ONLY if it is not a decimal rating (like .6 in - 6.6)
                  const extMatch = epFile.name.match(/\.([a-zA-Z0-9]+)$/);
                  if (extMatch) {
                    const ext = extMatch[1].toLowerCase();
                    if (isNaN(Number(ext)) && ext.length >= 2 && ext.length <= 5) {
                      titleStr = epFile.name.substring(0, epFile.name.lastIndexOf('.'));
                    }
                  }
                  
                  // 2. Extract rating and clean title if format is "Title - Rating"
                  const ratingMatch = titleStr.match(/^(.*?)\s*[-–—]\s*([0-9]+(?:\.[0-9]+)?)$/);
                  if (ratingMatch) {
                    titleStr = ratingMatch[1].trim();
                    epRating = parseFloat(ratingMatch[2]);
                  } else {
                    titleStr = titleStr.replace(/\.[^/.]+$/, "");
                  }
                  
                  let epYear = undefined;
                  
                  // Extract from description if available
                  if (epFile.description) {
                    try {
                      const descObj = JSON.parse(epFile.description);
                      if (descObj.year) epYear = String(descObj.year);
                      if (descObj.rating && epRating === undefined) epRating = Number(descObj.rating);
                    } catch (e) {
                      const yMatch = epFile.description.match(/\b(19\d\d|20\d\d)\b/);
                      if (yMatch) epYear = yMatch[1];
                      if (epRating === undefined) {
                        const rMatch = epFile.description.match(/\b([0-9](\.[0-9])?|10(\.0)?)\b/);
                        if (rMatch) epRating = Number(rMatch[1]);
                      }
                    }
                  }
                  
                  // Extract from title if not found yet
                  if (!epYear) {
                    const yMatch = titleStr.match(/(?:^|\s|\(|\[)(19\d\d|20\d\d)(?:\s|\)|\]|$)/);
                    if (yMatch) epYear = yMatch[1];
                  }
                  if (!epRating) {
                    const rMatch = titleStr.match(/(?:^|\s|\(|\[)([0-9](\.[0-9])?|10(\.0)?)(?:\s|\)|\]|$)/);
                    if (rMatch) epRating = Number(rMatch[1]);
                  }

                  seasonEpisodes.push({
                    id: epFile.id,
                    title: titleStr,
                    video: getDirectLink(epFile.id),
                    size: epFile.size || '',
                    thumbnail: epFile.thumbnailLink || '',
                    duration: epFile.videoMediaMetadata?.durationMillis ? parseInt(epFile.videoMediaMetadata.durationMillis) / 1000 : undefined,
                    year: epYear,
                    rating: epRating
                  });
                }
              }
              seasonEpisodes.sort((a: any, b: any) => {
                const numA = parseEpisodeNumber(a.title);
                const numB = parseEpisodeNumber(b.title);
                if (numA !== numB) return numA - numB;
                return a.title.localeCompare(b.title, undefined, { numeric: true, sensitivity: 'base' });
              });
              
              // Map year/rating from seasonInfo to episodes if not already parsed
              seasonEpisodes.forEach(ep => {
                if (seasonInfo.rating && !ep.rating) ep.rating = seasonInfo.rating;
                if (seasonInfo.year && !ep.year) ep.year = seasonInfo.year;
              });
              
              seasons.push({
                id: sf.id,
                name: sf.name,
                cover: seasonCover,
                episodes: seasonEpisodes
              });
            } catch (err) {
              console.error(`Error scanning episodes for season ${sf.name}`, err);
            }
          }
        } else {
          const directEpisodes = files.filter((f: any) => f.mimeType.startsWith('video/') && !f.name.toLowerCase().includes('trailer'));
          if (directEpisodes.length > 0) {
            const seasonEpisodes = directEpisodes.map((f: any) => {
              let titleStr = f.name;
              let epRating = undefined;
              
              // 1. Remove standard video extension ONLY if it is not a decimal rating (like .6 in - 6.6)
              const extMatch = f.name.match(/\.([a-zA-Z0-9]+)$/);
              if (extMatch) {
                const ext = extMatch[1].toLowerCase();
                if (isNaN(Number(ext)) && ext.length >= 2 && ext.length <= 5) {
                  titleStr = f.name.substring(0, f.name.lastIndexOf('.'));
                }
              }
              
              // 2. Extract rating and clean title if format is "Title - Rating"
              const ratingMatch = titleStr.match(/^(.*?)\s*[-–—]\s*([0-9]+(?:\.[0-9]+)?)$/);
              if (ratingMatch) {
                titleStr = ratingMatch[1].trim();
                epRating = parseFloat(ratingMatch[2]);
              } else {
                titleStr = titleStr.replace(/\.[^/.]+$/, "");
              }
              
              let epYear = undefined;
              
              if (f.description) {
                try {
                  const descObj = JSON.parse(f.description);
                  if (descObj.year) epYear = String(descObj.year);
                  if (descObj.rating && epRating === undefined) epRating = Number(descObj.rating);
                } catch (e) {
                  const yMatch = f.description.match(/\b(19\d\d|20\d\d)\b/);
                  if (yMatch) epYear = yMatch[1];
                  if (epRating === undefined) {
                    const rMatch = f.description.match(/\b([0-9](\.[0-9])?|10(\.0)?)\b/);
                    if (rMatch) epRating = Number(rMatch[1]);
                  }
                }
              }
              
              if (!epYear) {
                const yMatch = titleStr.match(/(?:^|\s|\(|\[)(19\d\d|20\d\d)(?:\s|\)|\]|$)/);
                if (yMatch) epYear = yMatch[1];
              }
              if (!epRating) {
                const rMatch = titleStr.match(/(?:^|\s|\(|\[)([0-9](\.[0-9])?|10(\.0)?)(?:\s|\)|\]|$)/);
                if (rMatch) epRating = Number(rMatch[1]);
              }
              
              return {
                id: f.id,
                title: titleStr,
                video: getDirectLink(f.id),
                size: f.size || '',
                thumbnail: f.thumbnailLink || '',
                duration: f.videoMediaMetadata?.durationMillis ? parseInt(f.videoMediaMetadata.durationMillis) / 1000 : undefined,
                year: epYear || info.year,
                rating: epRating || info.rating
              };
            });
            seasonEpisodes.sort((a: any, b: any) => {
              const numA = parseEpisodeNumber(a.title);
              const numB = parseEpisodeNumber(b.title);
              if (numA !== numB) return numA - numB;
              return a.title.localeCompare(b.title, undefined, { numeric: true, sensitivity: 'base' });
            });
            
            seasons.push({
              id: itemFolder.id,
              name: "الموسم 1",
              episodes: seasonEpisodes
            });
          }
        }
        
        // If we found seasons, let the main video default to the first episode of the first season
        if (seasons.length > 0 && seasons[0].episodes.length > 0) {
          videoUrl = seasons[0].episodes[0].video;
          videoId = seasons[0].episodes[0].id;
          videoSize = seasons[0].episodes[0].size || '';
          videoDuration = seasons[0].episodes[0].duration;
        }
      }
      
      targetList.push({
        id: itemFolder.id,
        title: itemFolder.name,
        cover: coverUrl,
        video: videoUrl,
        videoId: videoId,
        thumbnail: videoThumbnail,
        trailer: info.trailer || info.trailer_url || trailerUrl,
        trailerId: trailerId,
        size: videoSize,
        duration: videoDuration,
        info: info,
        seasons: seasons.length > 0 ? seasons : undefined
      });
    }
  }
  
  mediaCache = library;
  lastFetchTime = Date.now();
  console.log("Library scanned successfully.");
  return library;
}

app.get('/api/library', async (req, res) => {
  try {
    if (mediaCache && (Date.now() - lastFetchTime < CACHE_TTL)) {
      return res.json(mediaCache);
    }
    const library = await scanLibrary();
    res.json(library);
  } catch (error: any) {
    console.error("Library fetch error", error?.response?.data || error);
    res.status(500).json({ error: 'Failed to fetch library' });
  }
});

app.get('/api/image/:id', async (req, res) => {
  const { id } = req.params;
  const url = `https://www.googleapis.com/drive/v3/files/${id}?alt=media&key=${GDRIVE_API_KEY}`;
  try {
    const response = await axios.get(url, { responseType: 'stream' });
    if (response.headers['content-type']) res.setHeader('Content-Type', response.headers['content-type'] as string);
    if (response.headers['content-length']) res.setHeader('Content-Length', response.headers['content-length'] as string);
    // Pipe the image stream directly to the response
    response.data.pipe(res);
  } catch (error) {
    console.error(`Error fetching image ${id}`);
    res.status(500).send('Error fetching image');
  }
});

app.get('/api/video/:id', async (req, res) => {
  const { id } = req.params;
  const range = req.headers.range;
  const url = `https://www.googleapis.com/drive/v3/files/${id}?alt=media&key=${GDRIVE_API_KEY}`;

  const headers: Record<string, string> = {};
  if (range) {
    headers['Range'] = range;
  }

  try {
    const response = await axios({
      method: 'get',
      url: url,
      headers: headers,
      responseType: 'stream',
      validateStatus: (status) => status >= 200 && status < 300,
    });

    const contentType = response.headers['content-type'];
    const contentLength = response.headers['content-length'];
    const contentRange = response.headers['content-range'];
    const acceptRanges = response.headers['accept-ranges'] || 'bytes';

    if (contentType) res.setHeader('Content-Type', contentType as any);
    if (contentLength) res.setHeader('Content-Length', contentLength as any);
    if (contentRange) res.setHeader('Content-Range', contentRange as any);
    res.setHeader('Accept-Ranges', acceptRanges as any);

    res.status(response.status);
    
    // Crucial: Destroy the Google Drive download stream if the user closes/seeks the video player
    req.on('close', () => {
      response.data.destroy();
    });

    response.data.pipe(res);
  } catch (error: any) {
    console.error(`Error streaming video ${id}:`, error?.message);
    res.status(500).send('Error streaming video');
  }
});

// Vite Middleware for development
async function startServer() {
  if (process.env.NODE_ENV !== 'production') {
    const vite = await createViteServer({
      server: { middlewareMode: true },
      appType: 'spa',
    });
    app.use(vite.middlewares);
  } else {
    const distPath = path.join(process.cwd(), 'dist');
    app.use(express.static(distPath));
    app.get('*', (req, res) => {
      res.sendFile(path.join(distPath, 'index.html'));
    });
  }

  app.listen(PORT, '0.0.0.0', () => {
    console.log(`Server running on port ${PORT}`);
  });
}

startServer();
